int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int minDaysToMakeBouquets(int* bloomDays, int bloomDaysSize, int m, int k) {
    qsort(bloomDays, bloomDaysSize, sizeof(int), compare);
    int low = bloomDays[0], high = bloomDays[bloomDaysSize - 1];
    while (low < high) {
        int mid = low + (high - low) / 2;
        int count = 0, bouquets = 0;
        for (int i = 0; i < bloomDaysSize; i++) {
            if (bloomDays[i] <= mid) {
                count++;
                if (count == k) {
                    bouquets++;
                    count = 0;
                }
            } else {
                count = 0;
            }
        }
        if (bouquets >= m) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    if (low == high) {
        int count = 0, bouquets = 0;
        for (int i = 0; i < bloomDaysSize; i++) {
            if (bloomDays[i] <= low) {
                count++;
                if (count == k) {
                    bouquets++;
                    count = 0;
                }
            } else {
                count = 0;
            }
        }
        if (bouquets >= m) {
            return low;
        } else {
            return -1;
        }
    }
    return -1;
}

